import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

const Header = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const activeClass = 'text-blue-800 font-medium px-3';
  const inactiveClass = 'text-blue-600 hover:text-blue-800 font-medium px-3 ';

  return (
    <header className="bg-green-300 shadow-md px-4 py-2 flex justify-between items-center fixed w-full z-50 top-0 left-0 border-black-600">
      <div
        className="text-blue-600 font-bold text-xl cursor-pointer select-none"
        onClick={() => {
          navigate('/app/dashboard');
          setMobileMenuOpen(false);
        }}
      >
        DocSpot
      </div>
      <nav className="hidden md:flex space-x-4 bg-green-300 border-black">
        <NavLink to="/app/dashboard"  className={({ isActive }) => (isActive ? activeClass : inactiveClass)} style={({ isActive }) => ({ borderColor: isActive ? '#22c55e' : 'transparent', backgroundColor: isActive ? '#bbf7d0' : 'transparent' })}>
          Dashboard
        </NavLink>
        <NavLink to="/app/appointments" className={({ isActive }) => (isActive ? activeClass : inactiveClass)} style={({ isActive }) => ({ borderColor: isActive ? '#2563eb' : 'transparent' })}>
          Appointments
        </NavLink>
        <NavLink to="/app/book-appointment" className={({ isActive }) => (isActive ? activeClass : inactiveClass)} style={({ isActive }) => ({ borderColor: isActive ? '#2563eb' : 'transparent' })}>
          Book Appointment
        </NavLink>
        <NavLink to="/app/edit-profile" className={({ isActive }) => (isActive ? activeClass : inactiveClass)} style={({ isActive }) => ({ borderColor: isActive ? '#2563eb' : 'transparent' })}>
          Edit Profile
        </NavLink>
        <NavLink to="/app/change-password" className={({ isActive }) => (isActive ? activeClass : inactiveClass)} style={({ isActive }) => ({ borderColor: isActive ? '#2563eb' : 'transparent' })}>
          Change Password
        </NavLink>
        <button
          onClick={handleLogout}
          className="text-blue-600 hover:text-blue-800 font-medium px-3 border-b-2 border-transparent hover:border-black-600"
        >
          Logout
        </button>
      </nav>
      <div className="md:hidden flex items-center">
        <button
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
          className="text-blue-600 focus:outline-none focus:ring-2 focus:ring-inset focus:ring-blue-600"
          aria-label="Toggle menu"
        >
          {mobileMenuOpen ? (
            <svg className="h-6 w-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          ) : (
            <svg className="h-6 w-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          )}
        </button>
      </div>
      {mobileMenuOpen && (
        <nav className="md:hidden bg-white shadow-md px-2 pt-2 pb-3 space-y-1">
          <NavLink
            to="/app/dashboard"
            className={({ isActive }) => (isActive ? activeClass : inactiveClass)}
            onClick={() => setMobileMenuOpen(false)}
          >
            Dashboard
          </NavLink>
          <NavLink
            to="/app/appointments"
            className={({ isActive }) => (isActive ? activeClass : inactiveClass)}
            onClick={() => setMobileMenuOpen(false)}
          >
            Appointments
          </NavLink>
          <NavLink
            to="/app/book-appointment"
            className={({ isActive }) => (isActive ? activeClass : inactiveClass)}
            onClick={() => setMobileMenuOpen(false)}
          >
            Book Appointment
          </NavLink>
          <NavLink
            to="/app/edit-profile"
            className={({ isActive }) => (isActive ? activeClass : inactiveClass)}
            onClick={() => setMobileMenuOpen(false)}
          >
            Edit Profile
          </NavLink>
          <NavLink
            to="/app/change-password"
            className={({ isActive }) => (isActive ? activeClass : inactiveClass)}
            onClick={() => setMobileMenuOpen(false)}
          >
            Change Password
          </NavLink>
          <button
            onClick={() => {
              handleLogout();
              setMobileMenuOpen(false);
            }}
            className="text-blue-600 hover:text-blue-800 bg-green-300 font-medium px-3 w-full text-left"
          >
            Logout
          </button>
        </nav>
      )}
    </header>
  );
};

export default Header;
